test.describe("SauceDemo Login with Invalid Credentials", () => {

    let basePage: BasePage;

    test.beforeEach(async ({ page }) => {
        basePage = new BasePage(page, "SCRUM-86");
        await basePage.initialize();
            await basePage.page.goto("https://www.saucedemo.com/");
    });

    test("Invalid username and password", async ({ page }) => {
            await basePage.smartAction("I enter an invalid username \"not_a_real_username\" and password \"wrong_password\"", "not_a_real_usernamewrong_password");
