    });

    test("Locked account with incorrect password", async ({ page }) => {
            await basePage.smartAction("I have a locked account with username \"locked_user\" and password \"wrong_password\"", "locked_user");
            await basePage.smartAction("I enter the username \"locked_user\" and password \"wrong_password\"", "locked_user");
            await basePage.smartAction("I should see error message \"Account is currently locked\"");
    });

    test("Invalid credentials combinations (username=not_a_real_username, password=wrong_password, expected_error=Epic failure)", async ({ page }) => {
