    });

    test("Invalid credentials combinations (username=no_username, password=real_password, expected_error=Username required)", async ({ page }) => {
    });

    test("Invalid credentials combinations (username=real_username, password=wrong_password, expected_error=Wrong password)", async ({ page }) => {
    });

    test("Login button disabled with invalid credentials", async ({ page }) => {
            await basePage.smartAction("I enter an invalid username \"not_a_real_username\" and password \"wrong_password\"", "not_a_real_username|wrong_password");
            await basePage.smartAction("the login button should be disabled");
    });

    test("Error message shown on locked account", async ({ page }) => {
